import "./App.css";
import Navbar from "./component/Navbar";
import TextFrom from "./component/TextForm";
import React, { useState } from "react";
import Aleart from "./component/Aleart";
function App() {
  const [mode, setMode] = useState('light');
  const [modeRed, setModeRed] = useState('light');
  const [alert, setAlert] = useState(null);
  let toggleMode = () => {
    if (mode === 'light') {
      setMode('dark');
      document.body.style.backgroundColor='rgb(2 28 70)'
      showAleart("Dark Mode is on","primary")
    } else {
      setMode('light');
      document.body.style.backgroundColor='white'
      showAleart("Light Mode is on","success")
    }
  };
  let toggleRedMode = ()=>{
    if(modeRed==='light'){
      setModeRed('#8d0606')
      document.body.style.backgroundColor="#8d0606"
    }else{
      setModeRed('light')
      document.body.style.backgroundColor="white"
    }
  }
  let showAleart= (massage,type)=>{
    setAlert({
msg:massage,
type:type
    })
    setTimeout(() => {
      setAlert(null);
    },1500);
  } 

  return (
    <>
      <Navbar
        Title="Text Utiles"
        about="About Us"
        mode={mode}
        modeRed={modeRed}
        toggleMode={toggleMode}
        toggleRedMode={toggleRedMode}


      />
      <Aleart alert={alert} />
      <div className="container">
        <TextFrom  mode={mode}  showAleart={showAleart} heading="Enter Your Text To Analyse Below" />
      </div>
    </>
  );
}

export default App;
